INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (20001, 0, 23001, "", 2, 0, 0, 10, "", 20, 320);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (40011, 125801, 24001, "もうすぐ、みなさまに\nお会いできるのですね。\n胸が高鳴ってしまいます……\n", 2, 1, 0, 1, "リリ", 1, 321);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (40011, 126001, 24001, "初めまして、クリアです♪\nみなさんと一緒に冒険するの\nとっても楽しみにしてます", 2, 1, 0, 2, "クリア", 1, 322);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (40011, 126101, 24001, "んーと。\nこれ、あげる。\nはい", 2, 1, 0, 3, "プレシア", 1, 323);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (40011, 125801, 24001, "あらためまして……\n【アルターメイデン】の\nギルドマスター、リリと申します", 2, 2, 0, 4, "リリ", 1, 324);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (40011, 126001, 24001, "こんにちは、お兄さん♪\n【アルターメイデン】の\nクリアです", 2, 2, 0, 5, "クリア", 1, 325);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (40011, 126101, 24001, "お兄。\nきてくれて、うれしい", 2, 2, 0, 6, "プレシア", 1, 326);
